manipulate-scene.sql-check:
DELETE FROM passengers
WHERE name IN (
SELECT b.name
FROM bus_station b
);

game.initial-sql-script:
CREATE TABLE passengers (
  passenger_id INT,
  name VARCHAR(100),
  passport_no VARCHAR(50),
  nationality VARCHAR(50)
);
INSERT INTO passengers VALUES (1, 'Alice Anson', 'P123456', 'USA');
INSERT INTO passengers VALUES (2, 'Bob Bently', 'P789012', 'Germany');
